import React, { useState, useContext } from 'react';
import { AppContext } from '../context/AppContext';

const AdminPage = () => {
  const { products, setProducts, user } = useContext(AppContext);
  const [form, setForm] = useState({ name: '', price: '', img: '', category: 'Running' });
  const [editId, setEditId] = useState(null);

  // Защита: если зашел не админ, ничего не показываем
  if (user?.role !== 'admin') {
    return (
      <div className="container" style={{padding: '50px', textAlign: 'center'}}>
        <h1>Доступ запрещен</h1>
        <p>У вас нет прав администратора.</p>
      </div>
    );
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    const isEdit = editId !== null;
    const url = isEdit ? `http://localhost:3001/products/${editId}` : 'http://localhost:3001/products';
    const method = isEdit ? 'PUT' : 'POST';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form)
      });

      if (res.ok) {
        const data = await res.json();
        if (isEdit) {
          setProducts(products.map(p => p.id === editId ? data : p));
          alert('Товар обновлен!');
        } else {
          setProducts([...products, data]);
          alert('Товар добавлен!');
        }
        // Сброс формы
        setForm({ name: '', price: '', img: '', category: 'Running' });
        setEditId(null);
      }
    } catch (err) {
      alert('Ошибка при сохранении!');
    }
  };

  const startEdit = (p) => {
    setEditId(p.id);
    setForm({ name: p.name, price: p.price, img: p.img, category: p.category });
    window.scrollTo(0, 0); // Поднимаем экран к форме
  };

  return (
    <div className="container">
      <h2 style={{margin: '20px 0'}}>Управление товарами (CRUD)</h2>
      
      {/* Форма добавления/редактирования */}
      <div className="auth-box" style={{maxWidth: '600px', margin: '20px 0'}}>
        <h3>{editId ? 'Редактировать товар' : 'Добавить новый кроссовок'}</h3>
        <form onSubmit={handleSubmit}>
          <input 
            placeholder="Название модели" 
            value={form.name} 
            onChange={e => setForm({...form, name: e.target.value})} 
            required 
          />
          <input 
            type="number" 
            placeholder="Цена (KZT)" 
            value={form.price} 
            onChange={e => setForm({...form, price: Number(e.target.value)})} 
            required 
          />
          <input 
            placeholder="URL картинки" 
            value={form.img} 
            onChange={e => setForm({...form, img: e.target.value})} 
            required 
          />
          <button type="submit" style={{background: editId ? '#28a745' : '#007bff'}}>
            {editId ? 'Сохранить изменения' : 'Создать товар'}
          </button>
          {editId && (
            <button 
              type="button" 
              onClick={() => {setEditId(null); setForm({name:'', price:'', img:'', category:'Running'})}}
              style={{background: 'gray', marginTop: '10px'}}
            >
              Отмена
            </button>
          )}
        </form>
      </div>

      {/* Таблица текущих товаров */}
      <h3>Все товары в базе</h3>
      <table style={{width: '100%', borderCollapse: 'collapse', background: 'white', marginTop: '20px'}}>
        <thead>
          <tr style={{background: '#f4f4f4'}}>
            <th style={{padding: '10px', border: '1px solid #ddd'}}>Фото</th>
            <th style={{padding: '10px', border: '1px solid #ddd'}}>Название</th>
            <th style={{padding: '10px', border: '1px solid #ddd'}}>Цена</th>
            <th style={{padding: '10px', border: '1px solid #ddd'}}>Действие</th>
          </tr>
        </thead>
        <tbody>
          {products.map(p => (
            <tr key={p.id}>
              <td style={{padding: '10px', border: '1px solid #ddd', textAlign: 'center'}}>
                <img src={p.img} alt="" style={{width: '50px'}} />
              </td>
              <td style={{padding: '10px', border: '1px solid #ddd'}}>{p.name}</td>
              <td style={{padding: '10px', border: '1px solid #ddd'}}>{p.price} KZT</td>
              <td style={{padding: '10px', border: '1px solid #ddd', textAlign: 'center'}}>
                <button onClick={() => startEdit(p)} style={{width: 'auto', padding: '5px 15px'}}>Изменить</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

// ВОТ ЭТА СТРОКА САМАЯ ВАЖНАЯ!
export default AdminPage;
